[Fact]
public void ShouldWrapCellContentAtDelimiterWhenExceedingMaxWidth()
{
    // Arrange
    var table = new ConsoleTable("Column1");
    table.MaxWidth = 10;
    table.SetWordBreakDelimiter(' ');

    // "LongWord1 LongWord2" is 19 characters. 
    // MaxWidth is 10. The first 10 characters are "LongWord1 ".
    // However, to test the mid-word split logic, we use a string where the 10th char is inside a word.
    // "WordAlpha WordBeta" -> 10 chars is "WordAlpha ". Ends in space.
    // "WordAlpha123 WordBeta" -> 10 chars is "WordAlpha1". 
    // LastIndexOf(' ') in "WordAlpha1" is 9.
    table.AddRow("WordAlpha123 WordBeta");

    // Act
    var result = table.ToString();

    // Assert
    // The logic in SetFormats should split "WordAlpha123 WordBeta" 
    // at the last space before MaxWidth (10).
    // Expected Row 1: "WordAlpha123"
    // Expected Row 2: "WordBeta"

    Assert.Contains("WordAlpha123", result);
    Assert.Contains("WordBeta", result);

    // Verify the internal Rows list was expanded to handle the wrap
    // Initial Rows.Count was 1, should now be 2.
    // ToString calls SetFormats which modifies the collection.
    Assert.Equal(2, table.Rows.Count);
}
